import sys
from typing import List

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_word = False

class Solution:
    def longestWord(self, words: List[str]) -> str:
        root = TrieNode()
        for word in words:
            node = root
            for char in word:
                if char not in node.children:
                    node.children[char] = TrieNode()
                node = node.children[char]
            node.is_word = True

        longest_word = ""
        def dfs(node: TrieNode, prefix: str):
            nonlocal longest_word
            if node.is_word:
                if len(prefix) > len(longest_word):
                    longest_word = prefix
            for char, child_node in node.children.items():
                dfs(child_node, prefix + char)

        dfs(root, "")
        return longest_word

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        words = [next(it) for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    print(sol.longestWord(words))

