#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool is_word;
    TrieNode() : is_word(false) {}
};

class Solution {
public:
    string longestWord(vector<string>& words) {
        TrieNode* root = new TrieNode();
        for (const string& word : words) {
            TrieNode* node = root;
            for (char c : word) {
                if (node->children.find(c) == node->children.end()) {
                    node->children[c] = new TrieNode();
                }
                node = node->children[c];
            }
            node->is_word = true;
        }

        string longest_word;
        function<void(TrieNode*, string)> dfs = [&](TrieNode* node, string prefix) {
            if (node->is_word) {
                if (prefix.size() > longest_word.size()) {
                    longest_word = prefix;
                }
            }
            for (const auto& child : node->children) {
                dfs(child.second, prefix + child.first);
            }
        };
        dfs(root, "");
        return longest_word;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<string> words(n);
    for (int i = 0; i < n; i++) cin >> words[i];
    Solution sol;
    cout << sol.longestWord(words) << '\n';
    return 0;
}
